INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Alexander', 'unforgettable', 'Pour all ingredients into cocktail shaker filled with ice cubes. Shake and strain into a chilled cocktail glass.', 'cocktail', 'Sprinkle fresh ground nutmeg on top.', 'https://iba-world.com/iba-cocktail/alexander/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Americano', 'unforgettable', 'Mix the ingredients directly in an old fashioned glass filled with ice cubes. Add a splash of Soda Water. Stir gently.', 'old fashioned', 'Garnish with half orange slice and a lemon zest.', 'https://iba-world.com/iba-cocktail/americano/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Angel Face', 'unforgettable', 'Pour all ingredients into cocktail shaker filled with ice cubes. Shake and strain into a chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/angel-face/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Aviation', 'unforgettable', 'Add all ingredients into a cocktail shaker. Shake with cracked ice and strain into a chilled cocktail glass.', 'cocktail', 'Optional Maraschino Cherry.', 'https://iba-world.com/iba-cocktail/aviation/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Bee’s Knees', 'new_era', 'Stir honey with lemon and orange juices until it dissolves, add gin and shake with ice. Strain into a chilled cocktail glass.', 'cocktail', 'Optionally garnish with a lemon or orange zest.', 'https://iba-world.com/iba-cocktail/bees-knees/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Bellini', 'contemporary', 'Pour peach puree into the mixing glass with ice, add the Prosecco wine. Stir gently and pour in a chilled flute glass. NOTE: Puccini – Fresh Mandarin Orange Juice; Rossini – Fresh Strawberry Puree; Tintoretto –  Fresh Pomegranate Juice.', 'flute', 'N/A.', 'https://iba-world.com/iba-cocktail/bellini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Between The Sheets', 'unforgettable', 'Add all ingredients into a cocktail shaker. Shake with ice and strain into a chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/between-the-sheets/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Black Russian', 'contemporary', 'Pour the ingredients into the old fashioned glass filled with ice cubes. Stir gently. strain ingredients into old fashioned glass filled with ice. NOTE: WHITE RUSSIAN – Float fresh cream on the top and stir in slowly.', 'old fashioned', 'N/A', 'https://iba-world.com/iba-cocktail/black-russian/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Bloody Mary', 'contemporary', 'Stir gently all the ingredients in a mixing glass with ice, pour into rocks glass. NOTE: If requested served with ice, pour into highball glass.', 'highball', 'Celery, lemon wedge (Optional).', 'https://iba-world.com/iba-cocktail/bloody-mary/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Boulevardier', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Garnish with a orange zest, optionally a lemon zest.', 'https://iba-world.com/iba-cocktail/boulevardier/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Bramble', 'new_era', 'Pour all ingredients into cocktail shaker except the Crème de Mûre, shake well with ice, strain into chilled old fashioned glass filled with crushed ice, then pour the blackberry liqueur (Crème de Mûre) over the top of the drink, in a circular motion.', 'old fashioned', 'Garnish optionally with a lemon slice and blackberries.', 'https://iba-world.com/iba-cocktail/bramble/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Brandy Crusta', 'unforgettable', 'Mix together all ingredients with ice cubes in a mixing glass and strain into a prepared slim cocktail glass.', 'cocktail', 'Rub a slice of orange (or lemon) around the rim of the glass and dip it in pulverized white sugar, so that the sugar will adhere to the edge of the glass. Carefully curling place the orange/lemon peel around the inside of the glass.', 'https://iba-world.com/iba-cocktail/brandy-crusta/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Caipirinha', 'contemporary', 'Place lime and sugar into a double old fashioned glass and muddle gently. Fill the glass with cracked ice and add Cachaça. Stir gently to involve ingredients. Note: Caipiroska – Instead of Cachaça use Vodka; Caipirissima – Instead of Cachaça use Rum. Caipirão – Instead of Cachaça use Licor Beirão.', 'old fashioned', 'N/A', 'https://iba-world.com/iba-cocktail/caipirinha/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Canchanchara', 'new_era', 'Mix honey with water and lime juice and spread the mixture on the bottom and sides of the glass. Add cracked ice, and then the rum. End by energetically stirring from bottom to top.', NULL, 'Garnish with a lime wedge.', 'https://iba-world.com/iba-cocktail/canchanchara/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Cardinale', 'contemporary', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Garnish with a lemon zest.', 'https://iba-world.com/iba-cocktail/cardinale/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Casino', 'unforgettable', 'Pour all ingredients into cocktails shaker, shake well with ice, strain into chilled rocks glass with ice.', 'rocks', 'Garnish with a lemon zest and a maraschino cherry.', 'https://iba-world.com/iba-cocktail/casino/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Champagne Cocktail', 'contemporary', 'Place the sugar cube with 2 dashes of bitters in a large Champagne glass, add the cognac. Pour gently chilled Champagne.', NULL, 'Garnish with orange zest and maraschino cherry.', 'https://iba-world.com/iba-cocktail/champagne-cocktail/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Chartreuse Swizzle', 'new_era', 'Pour all ingredients into a tall glass, add pebble ice. With the help of a swizzle stick (or cocktail spoon) mix vigorously, complete by filling the glass with more pebble ice.', NULL, 'Garnish with mint leaves and grated nutmeg.', 'https://iba-world.com/iba-cocktail/chartreuse-swizzle/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Clover Club', 'unforgettable', 'Pour all ingredients into cocktails shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'Fresh raspberries.', 'https://iba-world.com/iba-cocktail/clover-club/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Corpse Reviver #2', 'contemporary', 'Pour all ingredients into shaker with ice. Shake well and strain in chilled cocktail glass.', 'cocktail', 'Garnish with an orange zest.', 'https://iba-world.com/iba-cocktail/corpse-reviver-2/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Cosmopolitan', 'contemporary', 'Add all ingredients into cocktail shaker filled with ice. Shake well and strain into large cocktail glass.', 'cocktail', 'Garnish with lemon twist.', 'https://iba-world.com/iba-cocktail/cosmopolitan/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Cuba Libre', 'contemporary', 'Build all ingredients in a highball glass filled with ice.', 'highball', 'Garnish with lime wedge.', 'https://iba-world.com/iba-cocktail/cuba-libre/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Daiquiri', 'unforgettable', 'In a cocktail shaker add all ingredients. Stir well to dissolve the sugar. Add ice and shake. Strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/daiquiri/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Dark ‘N’ Stormy', 'new_era', 'In a highball glass filled with ice pour the ginger beer and top floating with the Rum.', 'highball', 'Garnish with a lime wedge or slice.', 'https://iba-world.com/iba-cocktail/dark-n-stormy/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Don’s Special Daiquiri', 'new_era', 'Blend for a few seconds in a milkshake mixer with  crushed ice and pour into a footed copo glass. Fill the glass with more crushed ice.', NULL, 'Garnish with 1/2 passion fruit', 'https://iba-world.com/iba-cocktail/dons-special-daiquiri/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Dry Martini', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled martini cocktail glass.', 'cocktail', 'Squeeze oil from lemon peel onto the drink, or garnish with a green olives if requested.', 'https://iba-world.com/iba-cocktail/dry-martini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Espresso Martini', 'new_era', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', '3 coffee beans', 'https://iba-world.com/iba-cocktail/espresso-martini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Fernandito', 'new_era', 'Pour the Fernet Branca into a double old fashioned glass with ice, fill the glass up with Cola. Gently stir.', 'old fashioned', 'N/A', 'https://iba-world.com/iba-cocktail/fernandito/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('French 75', 'contemporary', 'Pour all the ingredients, except Champagne, into a shaker. Shake well and strain into a Champagne flute. Top up with Champagne. Stir gently.', 'flute', 'N/A', 'https://iba-world.com/iba-cocktail/french-75/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('French Connection', 'contemporary', 'Pour all ingredients directly into old fashioned glass filled with ice cubes. Stir gently.', 'old fashioned', 'N/A', 'https://iba-world.com/iba-cocktail/french-connection/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('French Martini', 'new_era', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'Squeeze oil from lemon peel onto the drink.', 'https://iba-world.com/iba-cocktail/french-martini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Garibaldi', 'contemporary', 'Build all ingredients in a highball glass filled with ice.', 'highball', 'Garnish with an orange wedge.', 'https://iba-world.com/iba-cocktail/garibaldi/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Gin Basil Smash', 'new_era', 'Add all ingredients into shaker with ice. Shake vigorously and pour into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/gin-basil-smash/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Gin Fizz', 'unforgettable', 'Shake all ingredients with ice except soda water. Pour into thin tall Tumbler glass , top with a splash soda water. NOTE: Serve without ice.', 'tumbler', 'Garnish with lemon slice, optional lemon zest.', 'https://iba-world.com/iba-cocktail/gin-fizz/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Grand Margarita', 'new_era', 'Rim the rock glass with good quality sea salt. Pour the ingredients into the  shaker. Add ice to both glass and shaker. Shake hard for 10 seconds. Strain the drink into the glass.', NULL, 'Garnish with a lime slice.', 'https://iba-world.com/iba-cocktail/grand-margarita/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Grasshopper', 'contemporary', 'Pour all ingredients into shaker filled with ice. Shake briskly for few seconds. Strain into chilled cocktail glass.', 'cocktail', 'N/A, optional mint leave.', 'https://iba-world.com/iba-cocktail/grasshopper/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Hanky Panky', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Orange zest.', 'https://iba-world.com/iba-cocktail/hanky-panky/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Hemingway Special', 'contemporary', 'Pour all ingredients into a shaker with ice. Shake well and strain into a large cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/hemingway-special/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Horse’s Neck', 'contemporary', 'Pour Cognac and ginger ale directly into highball glass with ice cubes. Stir gently. If preferred, add dashes of Angostura Bitter.', 'highball', 'Garnish with rind of one lemon spiral.', 'https://iba-world.com/iba-cocktail/horses-neck/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Iba Tiki', 'new_era', 'In a cocktail shaker muddle a thin slice of Gengibre, Pour all other ingredients. Shake vigorously with ice. Strain into a chilled Tiki glass filled with pebbled ice.', NULL, 'Garnish with citruses and dehydrated pineapple slice.', 'https://iba-world.com/iba-cocktail/iba-tiki/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Illegal', 'new_era', 'Pour all ingredients into the shaker. Shake vigorously with ice. Strain into a chilled cocktail glass, or “on the rocks” in a traditional clay or terracotta mug.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/illegal/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Irish Coffee', 'contemporary', 'Warm black coffee is poured into a preheated Irish coffee glass. Whiskey and at least one teaspoon of sugar is added and stirred until dissolved. Fresh thick chilled cream is carefully poured over the back of a spoon held just above the surface of the coffee. The layer of cream will float on the coffee without mixing. Plain sugar can be replaced with sugar syrup', NULL, 'N/A', 'https://iba-world.com/iba-cocktail/irish-coffee/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('John Collins', 'unforgettable', 'Pour all ingredients directly into highball filled with ice. Stir gently. NOTE: Use ‘Old Tom’ Gin for Tom Collins.', 'highball', 'Garnish with lemon slice and maraschino cherry.', 'https://iba-world.com/iba-cocktail/john-collins/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Jungle Bird', 'new_era', 'Pour all ingredients into a shaker with ice and shake. Strain into a rocks glass filled with ice.', 'rocks', 'Garnish with a pineapple wedge.', 'https://iba-world.com/iba-cocktail/jungle-bird/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Kir', 'contemporary', 'Pour Crème de Cassis into glass, top up with white wine. NOTE: Kir Royal – Use Champagne instead of white wine', NULL, 'N/A', 'https://iba-world.com/iba-cocktail/kir/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Last Word', 'unforgettable', 'Add all ingredients into a cocktail shaker. Shake with ice and strain into a chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/last-word/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Lemon Drop Martini', 'contemporary', 'Pour all ingredients into a shaker with ice. Shake well and strain into a chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/lemon-drop-martini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Long Island Iced Tea', 'contemporary', 'Add all ingredients into highball glass filled with ice. Stir gently.', 'highball', 'Garnish with lemon slice (Optional).', 'https://iba-world.com/iba-cocktail/long-island-iced-tea/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Mai-Tai', 'contemporary', 'Add all ingredients into a shaker with ice. Shake and pour into a double rocks glass or an highball glass. * The Martinique molasses rum used by Trader Vic was not an Agricole Rhum but a type of “rummy” from molasses.', 'highball', 'Garnish with pineapple spear, mint leaves and lime peel.', 'https://iba-world.com/iba-cocktail/mai-tai/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Manhattan', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Garnish with cocktail cherry.', 'https://iba-world.com/iba-cocktail/manhattan/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Margarita', 'contemporary', 'Add all ingredients into a shaker with ice. Shake and strain into a chilled cocktail glass.', 'cocktail', 'Half salt rim (Optional).', 'https://iba-world.com/iba-cocktail/margarita/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Martinez', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Lemon zest.', 'https://iba-world.com/iba-cocktail/martinez/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Mary Pickford', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/mary-pickford/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Mimosa', 'contemporary', 'Pour orange juice into flute glass and gently pour the sparkling wine. Stir gently. NOTE: Also known as Buck’s Fizz.', 'flute', 'Garnish with orange twist (optional).', 'https://iba-world.com/iba-cocktail/mimosa/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Mint Julep', 'contemporary', 'In Julep Stainless Steel Cup gently muddle the mint with sugar and water. Fill the glass with cracked ice, add the Bourbon and stir well until the cup frosts.', NULL, 'Garnish with a mint sprig.', 'https://iba-world.com/iba-cocktail/mint-julep/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Missionary’s Downfall', 'new_era', 'Blend all the ingredients with half cup of crushed ice. Serve it in a Coppa grande.', NULL, 'Garnish with mint sprig and a slice of pineapple.', 'https://iba-world.com/iba-cocktail/missionarys-downfall/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Mojito', 'contemporary', 'Mix mint springs with sugar and lime juice. Add splash of soda water and fill the glass with ice. Pour the rum and top with soda water. Light stir to involve all ingredients.', NULL, 'Garnish with sprigs of mint and slice of lime.', 'https://iba-world.com/iba-cocktail/mojito/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Monkey Gland', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/monkey-gland/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Moscow Mule', 'contemporary', 'In an Mule Cup or rocks glass, combine the vodka and ginger beer. Add lime juice and gently stir to involve all ingredients.', 'rocks', 'Garnish with a lime slice.', 'https://iba-world.com/iba-cocktail/moscow-mule/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Naked And Famous', 'new_era', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/naked-and-famous/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Negroni', 'unforgettable', 'Pour all ingredients directly into chilled old fashioned glass filled with ice. Stir gently.', 'old fashioned', 'Garnish with half orange slice.', 'https://iba-world.com/iba-cocktail/negroni/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('New York Sour', 'new_era', 'Pour all ingredients into the shaker. Shake vigorously with ice. Strain into a chilled rocks glass filled with ice. Float the wine on top.', 'rocks', 'Garnish with lemon or orange zest with cherry.', 'https://iba-world.com/iba-cocktail/new-york-sour/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Old Cuban', 'new_era', 'Pour all ingredients into cocktail shaker except the wine, shake well with ice, strain into chilled elegant cocktail glass. Top up with the sparkling wine.', 'cocktail', 'Garnish with mint springs.', 'https://iba-world.com/iba-cocktail/old-cuban/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Old Fashioned', 'unforgettable', 'Place sugar cube in old fashioned glass and saturate with bitter, add few dashes of plain water. Muddle until dissolved. Fill the glass with ice cubes and add whiskey. Stir gently.', 'old fashioned', 'Garnish with orange slice or zest, and a cocktail cherry.', 'https://iba-world.com/iba-cocktail/old-fashioned/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Paloma', 'new_era', 'Poor the tequila into a highball glass, squeeze the lime juice. Add ice and salt, fill up pink grapefruit soda. Stir gently.', 'highball', 'Garnish with a slice of lime.', 'https://iba-world.com/iba-cocktail/paloma/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Paper Plane', 'new_era', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/paper-plane/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Paradise', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/paradise/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Penicillin', 'new_era', 'Muddle fresh ginger in a shaker and add the remaining ingredients except for the Islay single malt whisky. Fill the shaker with ice and shake. Fine train into a chilled Old Fashioned glass with ice. Float the single malt whisky on top.', 'old fashioned', 'Garnish with candied ginger slices.', 'https://iba-world.com/iba-cocktail/penicillin/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Pina Colada', 'contemporary', 'Blend all the ingredients with ice in a electric blender, pour into a large glass and serve with straws. Note: Historically a few drops of fresh lime juice was added to taste. 4 slices of fresh pineapple can be used instead of juice', NULL, 'Garnish with a slice of pineapple with a cocktail cherry.', 'https://iba-world.com/iba-cocktail/pina-colada/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Pisco Punch', 'new_era', 'Gentle mash the simple syrup with the cloves, add the remaining ingredients except the wine. Shake vigorously and double strain into a large goblet. Add the wine on top and gently stir.', NULL, 'N/A', 'https://iba-world.com/iba-cocktail/pisco-punch/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Pisco Sour', 'contemporary', 'Add all ingredients into a shaker with ice. Shake and strain into a chilled goblet glass.', NULL, 'Few dashes of Amargo bitters on top as an aromatic garnish.', 'https://iba-world.com/iba-cocktail/pisco-sour/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Planters Punch', 'unforgettable', 'Pour all ingredients directly in a small tumbler or a typical terracotta glass. NOTE: Add dilution up to taste, it can be given by water, ice or fresh juices.', 'tumbler', 'Garnish with orange zest.', 'https://iba-world.com/iba-cocktail/planters-punch/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Porn Star Martini', 'new_era', 'Pour all ingredients into cocktail shaker, shake well with ice, double strain into a large chilled cocktail glass. Accompany with a shot of champagne.', 'cocktail', 'Garnish with passion fruit cup and sugar.', 'https://iba-world.com/iba-cocktail/porn-star-martini/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Porto Flip', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'Sprinkle with fresh ground nutmeg.', 'https://iba-world.com/iba-cocktail/porto-flip/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Rabo De Galo', 'contemporary', 'Combine all the ingredients into a rocks glass, add ice and stir briefly.', 'rocks', 'Garnish with a orange twist.', 'https://iba-world.com/iba-cocktail/rabo-de-galo/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Ramos Fizz', 'unforgettable', 'Pour all ingredients except soda water in a cocktail shaker with ice. Shake for two minutes, double strain in a glass, pour the drink back in the shaker and hard shake without ice for one minute. Strain into a highball glass, top up with soda. NOTE: The drink was invented by Henry Ramos in 1888, at his bar Meyer’s Table d’Hôtel Internationale in New Orleans. The Ramos Fizz was originally shaken for 12 minutes by a crew of 30 bartenders who passed the shaker from one to another.', 'highball', 'N/A', 'https://iba-world.com/iba-cocktail/ramos-fizz/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Remember The Maine', 'unforgettable', 'Pour the absinthe into a coupe glass and swirl to completely coat the inside. Discard the absinthe and set the glass aside. Add the other ingredients to a mixing glass and fill it 3/4 full with ice. Stir until chilled, then strain into the glass rinsed with the absinthe.', 'coupe', 'Garnish with lemon zest.', 'https://iba-world.com/iba-cocktail/remember-the-maine/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Russian Spring Punch', 'new_era', 'Pour all ingredients into cocktail shaker except the sparkling wine, shake well with ice, strain into chilled tall tumbler glass filled with ice and top up with sparkling wine.', 'tumbler', 'Garnish with blackberries and optionally a lemon slice as well.', 'https://iba-world.com/iba-cocktail/russian-spring-punch/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Rusty Nail', 'unforgettable', 'Pour all ingredients directly into an old fashioned glass filled with ice. Stir gently.', 'old fashioned', 'Garnish with lemon zest.', 'https://iba-world.com/iba-cocktail/rusty-nail/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Sazerac', 'unforgettable', 'Rinse a chilled old-fashioned glass with the absinthe, add crushed ice and set it aside. Stir the remaining ingredients over ice in a mixing glass. Discard the ice and any excess absinthe from the prepared glass, strain the mixed drink into the glass. NOTE: The original recipe changed after the American Civil War, Rye Whiskey substituted Cognac as it became hard to obtain.', 'old fashioned', 'Garnish with lemon zest.', 'https://iba-world.com/iba-cocktail/sazerac/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Sea Breeze', 'contemporary', 'Build all ingredients in a highball glass filled with ice.', 'highball', 'Garnish with an orange zest and cherry.', 'https://iba-world.com/iba-cocktail/sea-breeze/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Sex On The Beach', 'contemporary', 'Build all ingredients in a highball glass filled with ice.', 'highball', 'Garnish with half orange slice.', 'https://iba-world.com/iba-cocktail/sex-on-the-beach/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Sherry Cobbler', 'new_era', 'Combine sherry, sugar and 2 quarter wheels each of orange and lemon in a shaker with ice, shake briskly, strain into a Julep cocktail cup filled with crushed ice.', NULL, 'Garnish with fresh berries, ¼ wheel each orange and lemon. Serve with straws.', 'https://iba-world.com/iba-cocktail/sherry-cobbler/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Sidecar', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/sidecar/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Singapore Sling', 'contemporary', 'Pour all ingredients into cocktail shaker filled with ice cubes. Shake well. Strain into Hurricane glass.', 'hurricane', 'Garnish with pineapple and maraschino cherry.', 'https://iba-world.com/iba-cocktail/singapore-sling/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('South Side', 'new_era', 'Pour all ingredients into a cocktail shaker, shake well with ice, double-strain into chilled cocktail glass. Note: If egg white is used shake vigorously.', 'cocktail', 'Garnish with mint springs.', 'https://iba-world.com/iba-cocktail/south-side/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Spicy Fifty', 'new_era', 'Pour all ingredients into a cocktail shaker, shake well with ice, double-strain into chilled cocktail glass.', 'cocktail', 'Garnish with a red chili pepper.', 'https://iba-world.com/iba-cocktail/spicy-fifty/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Spritz', 'new_era', 'Build all ingredients into a wine glass filled with ice. Stir gently. NOTE: There are other versions of the Spritz that use Campari, Cynar or Select instead of Aperol.', 'wine', 'Garnish with a slice of orange.', 'https://iba-world.com/iba-cocktail/spritz/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Stinger', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled martini cocktail glass.', 'cocktail', 'Optional mint leave.', 'https://iba-world.com/iba-cocktail/stinger/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Suffering Bastard', 'new_era', 'Pour all ingredients into cocktail shaker except the ginger beer, shake well with ice. Pour unstrained into a Collins glass or in the original. S. Bastard mug and top up with ginger beer.', 'collins', 'Garnish with mint spring and optionally an orange slice as well.', 'https://iba-world.com/iba-cocktail/suffering-bastard/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Tequila Sunrise', 'contemporary', 'Pour tequila and orange juice directly into highball glass filled with ice cubes. Add the grenadine syrup to create chromatic effect (sunrise), do not stir.', 'highball', 'Garnish with half orange slice or an orange zest.', 'https://iba-world.com/iba-cocktail/tequila-sunrise/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Three Dots And A Dash', 'new_era', 'Pour all ingredients in a Blender with 12 ounces of crushed ice, flash blend, pour the drink into a footed copo glass. Fill the glass with more crushed ice.', NULL, 'Garnish with three cherries and a rectangular chunk of pineapple.', 'https://iba-world.com/iba-cocktail/three-dots-and-a-dash/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Tipperary', 'new_era', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled martini cocktail glass.', 'cocktail', 'Garnish with a slice of orange.', 'https://iba-world.com/iba-cocktail/tipperary/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Tommy’s Margarita', 'new_era', 'Pour all ingredients into a cocktail shaker, shake well with ice, strain into chilled rocks glass filled with ice.', 'rocks', 'Garnish with a lime slice.', 'https://iba-world.com/iba-cocktail/tommys-margarita/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Trinidad Sour', 'new_era', 'Pour all ingredients into a cocktail shaker, shake well with ice. Strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/trinidad-sour/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Tuxedo', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled martini cocktail glass.', 'cocktail', 'Garnish with cherry and lemon zest.', 'https://iba-world.com/iba-cocktail/tuxedo/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Ve.N.To', 'new_era', 'Pour all ingredients into the shaker. Shake vigorously with ice. Strain into a chilled small tumbler glass filled with ice. NOTE: *If desired water can be replaced by chamomile infusion in the honey mix.', 'tumbler', 'Garnish with lemon zest and white grapes.', 'https://iba-world.com/iba-cocktail/ve-n-to/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Vesper', 'contemporary', 'Pour all ingredients into cocktail shaker filled with ice cubes. Shake and strain into a chilled cocktail glass.', 'cocktail', 'Garnish with lemon zest.', 'https://iba-world.com/iba-cocktail/vesper/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Vieux Carré', 'unforgettable', 'Pour all ingredients into mixing glass with ice cubes. Stir well. Strain into chilled cocktail glass.', 'cocktail', 'Garnish with orange zest and maraschino cherry.', 'https://iba-world.com/iba-cocktail/vieux-carre/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Whiskey Sour', 'unforgettable', 'Pour all ingredients into cocktail shaker filled with ice. Shake well. Strain into cobbler glass. If served “On the rocks”, strain ingredients into old fashioned glass filled with ice. NOTE: If egg white is used shake little harder to release and incorporate the foam from the egg white.', 'old fashioned', 'Garnish with half orange slice and maraschino cherry, optionally use orange zest.', 'https://iba-world.com/iba-cocktail/whiskey-sour/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('White Lady', 'unforgettable', 'Pour all ingredients into cocktail shaker, shake well with ice, strain into chilled cocktail glass.', 'cocktail', 'N/A', 'https://iba-world.com/iba-cocktail/white-lady/');
INSERT INTO recipe (name, iba_category, method, glass, garnish, source_url) VALUES ('Zombie', 'contemporary', 'Add all ingredients into an electric blender with 170 grams of cracked ice. With pulse bottom blend for a few seconds. Serve in a tall tumbler glass. Note: *Donn’s Mix: 2 parts of fresh yellow grapefruit and 1 part of cinnamon syrup', 'tumbler', 'Garnish with mint leaves.', 'https://iba-world.com/iba-cocktail/zombie/');
